def register(add_locale, hero_block):
    def ext(
        code, meta_lang, title, desc, lang_label, nav, catch, headline, f1, f2, f3, f4,
        cta, cta2, trust, alt, pt, pi, ps, bt, bi, ft, fi, ut, ui, pr, ct, cl, cb,
    ):
        add_locale(
            code, meta_lang, title, desc, lang_label, nav,
            hero_block(catch, headline, f1, f2, f3, f4, cta, cta2, trust, alt),
            pt, pi, ps, bt, bi, ft, fi, ut, ui, pr, ct, cl, cb,
        )

    _register_all(ext)


def register_remaining(ext):
    _register_all(ext)
